import React, { useEffect, useState } from 'react';
import PendingSubmissions from './pages/PendingSubmissions';
import RhymesList from './pages/RhymesList';
import GiftsList from './pages/GiftsList';
import UsersList from './pages/UsersList';
import AddressesList from './pages/AddressesList';
import AuditLogs from './pages/AuditLogs';

const ACTIVE_PAGE_KEY = 'ginj-admin-active-page';

function App() {
  const [currentPage, setCurrentPage] = useState(() => localStorage.getItem(ACTIVE_PAGE_KEY) || 'pending');

  useEffect(() => {
    localStorage.setItem(ACTIVE_PAGE_KEY, currentPage);
  }, [currentPage]);

  return (
    <div style={{ padding: '24px', fontFamily: 'Arial, sans-serif' }}>
      <h1>GINJ Admin Dashboard</h1>
      <nav style={{ marginBottom: 24 }}>
        <button onClick={() => setCurrentPage('pending')} style={{ marginRight: 8 }}>
          Pending Submissions
        </button>
        <button onClick={() => setCurrentPage('rhymes')} style={{ marginRight: 8 }}>
          Rhymes List
        </button>
        <button onClick={() => setCurrentPage('gifts')} style={{ marginRight: 8 }}>
          Gift List
        </button>
        <button onClick={() => setCurrentPage('users')} style={{ marginRight: 8 }}>
          Users
        </button>
        <button onClick={() => setCurrentPage('addresses')} style={{ marginRight: 8 }}>
          Address Master
        </button>
        <button onClick={() => setCurrentPage('auditLogs')}>
          Audit Logs
        </button>
      </nav>
      {currentPage === 'pending' && <PendingSubmissions />}
      {currentPage === 'rhymes' && <RhymesList />}
      {currentPage === 'gifts' && <GiftsList />}
      {currentPage === 'users' && <UsersList />}
      {currentPage === 'addresses' && <AddressesList />}
      {currentPage === 'auditLogs' && <AuditLogs />}
    </div>
  );
}

export default App;
